var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"그럼 이상으로 비정기 국무회의를 폐회하겠습니다.","JPN":"それでは、これで臨時国務会議を閉会します。","ENG":"Then, the irregular cabinet meeting will end here.","TWN":"那麼，本次的臨時國務會議就此結束。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"참석자 분들께서는 각자 맡은 바 소임에 힘써 주십시오. 이상입니다.","JPN":"ご参席の方々におかれましては、各自の役割に尽力してください。以上です。","ENG":"Attendees, please perform your duties with diligence. That is all.","TWN":"請各位各司其職、各盡其責，以上。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 잠시 괜찮으시겠습니까.","JPN":"閣下、少々よろしいでしょうか。","ENG":"Sir, may I have a minute?","TWN":"總務，我有些話想和您談談。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"오, 자네로군. 그렇지 않아도 따로 한 번 부르려던 참이었는데.","JPN":"おお、君か。ちょうど個別に話をせねばと思っていたところだったんだ。","ENG":"Oh, it's you. I was actually going to call you in myself.","TWN":"喔，是你。我剛想要單獨和你談呢。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"그래, 일처리는 어떻게 되었나?","JPN":"それで、どうなったかね？","ENG":"So, how's the situation being handled?","TWN":"事情處理得怎麼樣？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"우선 우려하셨던 50호선 고속도로 인근에 발생한 침식체들에 대해선…","JPN":"まず、ご心配なさっていた50号線高速道路の近くで発生した侵食体については……","ENG":"First of all, about the C.O.s that appeared on I-50...","TWN":"關於您之前擔憂的50號線高速公路附近出沒的侵蝕體……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"발생 당시 있던 용병들과 샤레이드의 증원에 의해 제압되었습니다.","JPN":"発生当時、そこにいた傭兵たちとシャレードの増援により、制圧に成功しました。","ENG":"They were suppressed by the mercenaries that were in the area and reinforcements from Charade.","TWN":"已被案發現場的傭兵和查雷德的支援人力成功制伏。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":null,"text":{"KOREA":"샤레이드?","JPN":"シャレード？","ENG":"Charade?","TWN":"查雷德？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"오지만디아스를 태스크포스 자격으로 파견했더군요.","JPN":"オジマンディアスをタスクフォースの資格で派遣したのです。","ENG":"They deployed Ozymandias as a TASKFORCE.","TWN":"他們派來奧茲曼迪亞斯來。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아무래도 루이제 슈나이더 건과 관련해서, 미리 준비를 해 둔 모양새였습니다.","JPN":"どうやらルイーゼ・シュナイダーの件に関して、あらかじめ準備しておいた様子でした。","ENG":"It seemed that they had prepared in advance regarding the Louise Schneider case.","TWN":"可能是想為露易絲·修奈德事件提前做好準備。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"흐음…. 그렇군. 좋아.","JPN":"ふむ……そうか。よろしい。","ENG":"Hmm... I see. Very well.","TWN":"嗯……原來如此，好。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그 다음은, 수도 상공에 출몰했던 침식체에 대해서입니다만….","JPN":"続いて、首都上空に出現した侵食体についてですが……","ENG":"Next is regarding the C.O. that appeared in the capital's airspace...","TWN":"然後是關於首都上空出沒的侵蝕體……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"그 건은 이제 되었네. 침식 청정지대로서 건재하다면 더 들쑤실 것 없어.","JPN":"その件はもういい。侵食清浄区域として健在ならこれ以上騒ぎ立てる必要はない。","ENG":"I've heard enough about that one. No need to address it as long as the city is still a C.O.-free zone.","TWN":"那事就到此為止，既然已經恢復為無侵蝕區域，那就這樣吧。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"브레히트 중사라고 했던가?","JPN":"ブレヒト軍曹だったか？","ENG":"Sergeant Brecht, was it?","TWN":"她叫布萊希特中士？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":null,"text":{"KOREA":"요새 국민들 사이에서 인기가 하늘을 찌르더군.","JPN":"最近、国民の間で人気がうなぎ登りのようだな。","ENG":"Her popularity seems to have skyrocketed among the people.","TWN":"她最近似乎很受國民愛戴。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이미 정부군에서 영웅으로 선전하던 부사관입니다.","JPN":"過去に政府軍で英雄と称していた下士官です。","ENG":"She is an NCO who has already been promoted as a hero by the government.","TWN":"她之前就是一位被誇為英雄的中士。"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"이 기세라면 최연소 의원도 가능할 것으로 보입니다. 이미 접촉 의사를 타진하는 자들도….","JPN":"この勢いなら、最年少議員も可能かと。すでに接触を試みようとする者たちも……","ENG":"At this rate, she might become the youngest council member in the history of our country. Some have already contacted her...","TWN":"如果能延續這股氣勢，甚至當選最年輕議員也有可能。已經有些人在試圖去接觸她……"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"어떻게 처리할 수 없겠나?","JPN":"何とか処理はできないか？","ENG":"Can you handle it for me?","TWN":"你說能不能處理？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};